.darma-loader-button-dots {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  border-radius: 999px;
  background: var(--loader-color, #6366f1);
  padding: 12px 18px;
  color: #fff;
}
.darma-loader-button-dots i {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: currentColor;
  animation: darma-loader-button-dots-blink 0.95s ease-in-out infinite;
}
.darma-loader-button-dots i:nth-child(2) { animation-delay: 0.15s; }
.darma-loader-button-dots i:nth-child(3) { animation-delay: 0.3s; }
@keyframes darma-loader-button-dots-blink {
  0%, 100% { opacity: 0.28; transform: scale(0.8); }
  50% { opacity: 1; transform: scale(1); }
}

